const incoming = (typeof $json === 'object' && $json) ? $json : {};
const body = incoming.body && typeof incoming.body === 'object' ? incoming.body : {};
const payload = incoming.payload && typeof incoming.payload === 'object' ? incoming.payload : {};
const siteSlug = String(
  incoming.siteSlug ||
  incoming.site_slug ||
  body.siteSlug ||
  payload.siteSlug ||
  $env.SITE_SLUG ||
  ''
).trim().toLowerCase();
if (!siteSlug) {
  throw new Error('Missing siteSlug for Resolve Site Context');
}

const baseUrl = String($env.CONTENT_ENGINE_URL || '').replace(/\/$/, '');
if (!baseUrl) {
  throw new Error('Missing CONTENT_ENGINE_URL env var');
}

const internalToken = String($env.INTERNAL_API_TOKEN || '').trim();
if (!internalToken) {
  throw new Error('Missing INTERNAL_API_TOKEN env var');
}

const nf = (typeof fetch === 'function') ? null : require('node-fetch');
const fetchFn = (typeof fetch === 'function') ? fetch : (nf.default || nf);
const url = baseUrl + '/api/internal/sites/' + encodeURIComponent(siteSlug) + '/sanity-connection';

const response = await fetchFn(url, {
  method: 'GET',
  headers: {
    'x-internal-token': internalToken,
  },
});

const raw = await response.text();
let parsed = {};
try {
  parsed = raw ? JSON.parse(raw) : {};
} catch (error) {
  throw new Error('Invalid sanity-connection response for ' + siteSlug + ': ' + raw.slice(0, 220));
}

if (!response.ok || !parsed.ok || !parsed.sanity) {
  throw new Error('Cannot resolve site Sanity connection for ' + siteSlug + ': ' + (parsed.error || raw || response.status));
}

const sanity = parsed.sanity || {};
if (!sanity.projectId || !sanity.readToken || !sanity.writeToken) {
  throw new Error('Incomplete site Sanity connection for ' + siteSlug);
}

return {
  json: {
    ...incoming,
    siteSlug: parsed.siteSlug || siteSlug,
    sanity,
  }
};
